/* ==========================================================================
   Historia Argentina 1500–1900 — Estilos Base
   ==========================================================================
   Paleta: sepia/pergamino con acentos celeste y blanco (D004)
   Tipografía: Playfair Display (títulos), Source Serif 4 (citas), Lato (cuerpo)
   Layout: Timeline vertical con secciones full-width
   ========================================================================== */

/* ---------- Reset & Foundations ---------- */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: 'Lato', 'Helvetica Neue', sans-serif;
  font-weight: 300;
  line-height: 1.7;
  color: var(--color-text);
  background-color: var(--color-bg);
  overflow-x: hidden;
}

img, video {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

ul, ol {
  list-style: none;
}

/* ---------- CSS Custom Properties ---------- */

:root {
  /* Paleta sepia / pergamino */
  --color-bg:            #f5f0e8;
  --color-bg-warm:       #ede6d6;
  --color-text:          #3b2f20;
  --color-text-muted:    #7a6b5a;
  --color-sepia-light:   #f0e8d4;
  --color-sepia-mid:     #d4c4a0;
  --color-sepia-dark:    #8b7355;

  /* Acentos nacionales */
  --color-celeste:       #74acdf;
  --color-celeste-soft:  #a8cce8;
  --color-celeste-deep:  #4a8ab5;
  --color-blanco:        #ffffff;

  /* Acentos por período */
  --color-colonial:      #a08060;
  --color-revolucion:    #74acdf;
  --color-nacional:      #8b6b4a;

  /* Superficies */
  --color-card-bg:       #faf7f0;
  --color-card-border:   #e0d5c0;
  --color-divider:       #d4c4a0;

  /* Sombras */
  --shadow-soft:         0 2px 12px rgba(59, 47, 32, 0.08);
  --shadow-card:         0 1px 4px rgba(59, 47, 32, 0.06), 0 4px 16px rgba(59, 47, 32, 0.04);
  --shadow-elevated:     0 4px 24px rgba(59, 47, 32, 0.12);

  /* Tipografía */
  --font-display:        'Playfair Display', 'Georgia', serif;
  --font-body:           'Lato', 'Helvetica Neue', sans-serif;
  --font-serif:          'Source Serif 4', 'Georgia', serif;

  /* Espaciado */
  --space-xs:   0.25rem;
  --space-sm:   0.5rem;
  --space-md:   1rem;
  --space-lg:   2rem;
  --space-xl:   3rem;
  --space-2xl:  5rem;
  --space-3xl:  8rem;

  /* Layout */
  --content-width:       72rem;
  --content-narrow:      48rem;
  --nav-height:          3.5rem;

  /* Transiciones */
  --ease-out:            cubic-bezier(0.23, 1, 0.32, 1);
  --duration-fast:       150ms;
  --duration-normal:     300ms;
  --duration-slow:       600ms;
}

/* ---------- Textura de fondo global ---------- */

body::before {
  content: '';
  position: fixed;
  inset: 0;
  background-image:
    radial-gradient(ellipse at 20% 50%, rgba(160, 128, 96, 0.04) 0%, transparent 60%),
    radial-gradient(ellipse at 80% 20%, rgba(116, 172, 223, 0.03) 0%, transparent 50%);
  pointer-events: none;
  z-index: 0;
}

/* ---------- Header ---------- */

.site-header {
  position: relative;
  padding: var(--space-3xl) var(--space-lg) var(--space-2xl);
  text-align: center;
  background:
    linear-gradient(180deg, var(--color-bg-warm) 0%, var(--color-bg) 100%);
  border-bottom: 1px solid var(--color-divider);
  z-index: 1;
}

.site-header::after {
  content: '';
  position: absolute;
  bottom: -1px;
  left: 50%;
  transform: translateX(-50%);
  width: 6rem;
  height: 3px;
  background: linear-gradient(90deg, transparent, var(--color-celeste), transparent);
}

.header-inner {
  max-width: var(--content-narrow);
  margin: 0 auto;
}

.header-kicker {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-weight: 400;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  margin-bottom: var(--space-md);
}

.header-title {
  font-family: var(--font-display);
  font-size: clamp(2.2rem, 5vw, 3.8rem);
  font-weight: 900;
  line-height: 1.15;
  color: var(--color-text);
  margin-bottom: var(--space-lg);
}

.title-years {
  display: block;
  font-weight: 400;
  font-style: italic;
  font-size: 0.65em;
  color: var(--color-sepia-dark);
  margin-top: var(--space-xs);
}

.header-subtitle {
  font-family: var(--font-serif);
  font-size: 1.15rem;
  line-height: 1.8;
  color: var(--color-text-muted);
  max-width: 36rem;
  margin: 0 auto;
}

.alberdi-name {
  font-weight: 600;
  color: var(--color-text);
  white-space: nowrap;
}

/* ---------- Navegación ---------- */

.site-nav {
  position: sticky;
  top: 0;
  z-index: 100;
  background: rgba(245, 240, 232, 0.92);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--color-divider);
  padding: 0 var(--space-md);
}

.nav-list {
  display: flex;
  justify-content: center;
  gap: 0;
  max-width: var(--content-width);
  margin: 0 auto;
}

.nav-item {
  flex: 1;
  max-width: 16rem;
}

.nav-link {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.15rem;
  padding: var(--space-sm) var(--space-md);
  border-bottom: 3px solid transparent;
  transition: border-color var(--duration-normal) var(--ease-out),
              background var(--duration-normal) var(--ease-out);
}

.nav-link:hover {
  background: rgba(160, 128, 96, 0.06);
  border-bottom-color: var(--color-sepia-mid);
}

.nav-item--active .nav-link {
  border-bottom-color: var(--color-celeste);
}

.nav-years {
  font-family: var(--font-display);
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--color-text);
}

.nav-label {
  font-size: 0.7rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--color-text-muted);
}

/* ---------- Secciones de período ---------- */

.site-main {
  position: relative;
  z-index: 1;
}

.period {
  position: relative;
  padding: var(--space-3xl) var(--space-lg);
  border-bottom: 1px solid var(--color-divider);
}

.period-header {
  text-align: center;
  max-width: var(--content-narrow);
  margin: 0 auto var(--space-2xl);
}

.period-years {
  display: inline-block;
  font-family: var(--font-display);
  font-size: 0.85rem;
  font-weight: 700;
  letter-spacing: 0.15em;
  color: var(--color-text-muted);
  padding: var(--space-xs) var(--space-md);
  border: 1px solid var(--color-divider);
  border-radius: 2rem;
  margin-bottom: var(--space-md);
}

.period-title {
  font-family: var(--font-display);
  font-size: clamp(1.8rem, 3.5vw, 2.8rem);
  font-weight: 700;
  line-height: 1.2;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.period-scope {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-weight: 400;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-text-muted);
}

.period-body {
  max-width: var(--content-width);
  margin: 0 auto;
}

.period-intro {
  max-width: var(--content-narrow);
  margin: 0 auto var(--space-2xl);
}

.period-intro p {
  font-family: var(--font-serif);
  font-size: 1.1rem;
  line-height: 1.85;
  color: var(--color-text);
}

/* ---------- Acentos por período ---------- */

.period--colonial {
  background: linear-gradient(180deg, var(--color-bg) 0%, rgba(160, 128, 96, 0.04) 50%, var(--color-bg) 100%);
}

.period--colonial .period-years {
  border-color: var(--color-colonial);
  color: var(--color-colonial);
}

.period--revolucion {
  background: linear-gradient(180deg, var(--color-bg) 0%, rgba(116, 172, 223, 0.06) 50%, var(--color-bg) 100%);
}

.period--revolucion .period-years {
  border-color: var(--color-celeste);
  color: var(--color-celeste-deep);
}

.period--nacional {
  background: linear-gradient(180deg, var(--color-bg) 0%, rgba(139, 107, 74, 0.04) 50%, var(--color-bg) 100%);
}

.period--nacional .period-years {
  border-color: var(--color-nacional);
  color: var(--color-nacional);
}

/* ---------- Sección destacada (1800–1860) ---------- */

.period--featured {
  padding-top: calc(var(--space-3xl) + 2rem);
}

.period--featured::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg,
    transparent 10%,
    var(--color-celeste-soft) 30%,
    var(--color-celeste) 50%,
    var(--color-celeste-soft) 70%,
    transparent 90%
  );
}

.period--featured .period-title {
  font-size: clamp(2rem, 4vw, 3.2rem);
}

.period-featured-badge {
  position: absolute;
  top: var(--space-lg);
  left: 50%;
  transform: translateX(-50%);
  padding: var(--space-xs) var(--space-lg);
  background: var(--color-celeste);
  color: var(--color-blanco);
  font-family: var(--font-body);
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  border-radius: 2rem;
  box-shadow: 0 2px 8px rgba(116, 172, 223, 0.3);
}

/* ---------- Cita de Alberdi ---------- */

.alberdi-quote {
  margin: var(--space-xl) auto;
  padding: var(--space-lg) var(--space-xl);
  max-width: 36rem;
  border-left: 3px solid var(--color-celeste);
  background: rgba(116, 172, 223, 0.04);
  border-radius: 0 4px 4px 0;
}

.alberdi-quote p {
  font-family: var(--font-serif);
  font-size: 1.3rem;
  font-style: italic;
  line-height: 1.6;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.alberdi-quote cite {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-style: normal;
  color: var(--color-text-muted);
  display: block;
}

/* ---------- Grid de eventos (placeholder) ---------- */

.events-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(min(100%, 20rem), 1fr));
  gap: var(--space-lg);
  margin-top: var(--space-xl);
}

.event-card {
  position: relative;
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: 6px;
  padding: var(--space-lg);
  box-shadow: var(--shadow-card);
  transition: box-shadow var(--duration-normal) var(--ease-out),
              transform var(--duration-normal) var(--ease-out);
}

.event-card:hover {
  box-shadow: var(--shadow-elevated);
  transform: translateY(-2px);
}

.event-card--placeholder {
  opacity: 0.85;
}

.event-card__year {
  display: inline-block;
  font-family: var(--font-display);
  font-size: 0.8rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  color: var(--color-sepia-dark);
  padding: 2px var(--space-sm);
  border: 1px solid var(--color-sepia-mid);
  border-radius: 3px;
  margin-bottom: var(--space-sm);
}

.event-card__title {
  font-family: var(--font-display);
  font-size: 1.15rem;
  font-weight: 700;
  line-height: 1.3;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.event-card__excerpt {
  font-family: var(--font-serif);
  font-size: 0.95rem;
  line-height: 1.65;
  color: var(--color-text-muted);
}

/* Acentos en cards por período */

.period--colonial .event-card {
  border-top: 2px solid rgba(160, 128, 96, 0.3);
}

.period--revolucion .event-card {
  border-top: 2px solid rgba(116, 172, 223, 0.4);
}

.period--nacional .event-card {
  border-top: 2px solid rgba(139, 107, 74, 0.3);
}

/* ---------- Footer ---------- */

.site-footer {
  position: relative;
  padding: var(--space-2xl) var(--space-lg) var(--space-xl);
  background: var(--color-bg-warm);
  border-top: 1px solid var(--color-divider);
  z-index: 1;
}

.footer-inner {
  max-width: var(--content-narrow);
  margin: 0 auto;
  text-align: center;
}

.footer-alberdi {
  margin-bottom: var(--space-xl);
  padding-bottom: var(--space-xl);
  border-bottom: 1px solid var(--color-divider);
}

.footer-epigraph {
  font-family: var(--font-serif);
  font-size: 1.15rem;
  font-style: italic;
  line-height: 1.7;
  color: var(--color-text);
  margin-bottom: var(--space-sm);
}

.footer-cite {
  font-family: var(--font-body);
  font-size: 0.8rem;
  font-style: normal;
  color: var(--color-text-muted);
}

.footer-credits p {
  font-family: var(--font-body);
  font-size: 0.85rem;
  color: var(--color-text-muted);
  margin-bottom: var(--space-xs);
}

.footer-note {
  font-size: 0.75rem !important;
  max-width: 32rem;
  margin-left: auto;
  margin-right: auto;
}

.footer-hilo {
  margin-top: var(--space-md) !important;
  font-size: 0.8rem !important;
}

.footer-hilo strong {
  color: var(--color-text);
  font-weight: 700;
}

/* ---------- Responsivo ---------- */

@media (max-width: 48rem) {
  .site-header {
    padding: var(--space-2xl) var(--space-md) var(--space-xl);
  }

  .period {
    padding: var(--space-2xl) var(--space-md);
  }

  .nav-link {
    padding: var(--space-sm) var(--space-xs);
  }

  .nav-label {
    font-size: 0.6rem;
  }

  .nav-years {
    font-size: 0.75rem;
  }

  .events-grid {
    grid-template-columns: 1fr;
  }

  .alberdi-quote {
    padding: var(--space-md) var(--space-lg);
    margin-left: 0;
    margin-right: 0;
  }
}

@media (max-width: 30rem) {
  .nav-list {
    flex-direction: column;
    align-items: center;
    gap: 0;
  }

  .nav-item {
    width: 100%;
    max-width: none;
  }

  .nav-link {
    flex-direction: row;
    justify-content: center;
    gap: var(--space-sm);
    padding: var(--space-sm) var(--space-md);
  }
}

/* ---------- Utilidades ---------- */

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* ---------- Placeholder para futuros niveles de certeza (D009/D010) ---------- */

.certeza-hecho {
  /* Texto normal — sin estilo especial */
}

.certeza-opinion {
  border-left: 3px solid var(--color-celeste);
  padding-left: var(--space-md);
  font-style: italic;
}

.certeza-rumor {
  font-style: italic;
  opacity: 0.8;
}

.certeza-badge {
  display: inline-block;
  font-family: var(--font-body);
  font-size: 0.65rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  padding: 2px var(--space-sm);
  border-radius: 3px;
  vertical-align: middle;
}

.certeza-badge--hecho {
  background: rgba(59, 47, 32, 0.08);
  color: var(--color-text);
}

.certeza-badge--opinion {
  background: rgba(116, 172, 223, 0.12);
  color: var(--color-celeste-deep);
}

.certeza-badge--rumor {
  background: rgba(160, 128, 96, 0.1);
  color: var(--color-sepia-dark);
}

